@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public int TimeoutSeconds { get; set; } = 300;

    [Parameter] public EventCallback OnIdle { get; set; }

    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private System.Timers.Timer? _timer;
    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);

            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");

            await _module.InvokeVoidAsync("initialize", _element, _dotNetRef);

            _timer = new System.Timers.Timer(TimeoutSeconds * 1000);
            _timer.AutoReset = false;
            _timer.Elapsed += OnTimerElapsed;
            _timer.Start();
        }
    }

    [JSInvokable]
    public async Task NotifyActivity()
    {
        _timer?.Stop();
        _timer?.Start();

        if (_isIdle)
        {
            _isIdle = false;
            await InvokeAsync(async () => await OnActive.InvokeAsync());
        }
    }

    private async void OnTimerElapsed(object? sender, System.Timers.ElapsedEventArgs e)
    {
        if (!_isIdle)
        {
            _isIdle = true;
            await InvokeAsync(async () => await OnIdle.InvokeAsync());
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_timer is not null)
        {
            _timer.Elapsed -= OnTimerElapsed;
            _timer.Stop();
            _timer.Dispose();
            _timer = null;
        }

        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone
            }
            _module = null;
        }

        _dotNetRef?.Dispose();
        _dotNetRef = null;
    }
}

let handler = null;
let element = null;

const events = ['mousemove', 'keydown', 'click', 'scroll'];

export function initialize(el, dotNetRef) {
    element = el;
    handler = () => dotNetRef.invokeMethodAsync('NotifyActivity');

    for (const event of events) {
        element.addEventListener(event, handler, { passive: true });
    }
}

export function dispose() {
    if (element && handler) {
        for (const event of events) {
            element.removeEventListener(event, handler);
        }
    }
    handler = null;
    element = null;
}

